{
  "module": "01-layout.md",
  "group": "01 — Layout Components",
  "apiCount": 10,
  "apis": [
    {
      "name": "Flex",
      "purpose": "弹性布局容器组件，高效排列对齐子元素并分配剩余空间",
      "anchor": "flex",
      "status": "found"
    },
    {
      "name": "Column",
      "purpose": "沿垂直方向布局的线性容器",
      "anchor": "column",
      "status": "found"
    },
    {
      "name": "Row",
      "purpose": "沿水平方向布局的线性容器",
      "anchor": "row",
      "status": "found"
    },
    {
      "name": "Stack",
      "purpose": "堆叠容器，子组件按顺序入栈后一个覆盖前一个",
      "anchor": "stack",
      "status": "found"
    },
    {
      "name": "Scroll",
      "purpose": "可滚动容器组件，子组件尺寸超出父组件时可滚动",
      "anchor": "scroll",
      "status": "found"
    },
    {
      "name": "Grid",
      "purpose": "网格容器由行列分割的单元格组成的布局",
      "anchor": "grid",
      "status": "found"
    },
    {
      "name": "GridItem",
      "purpose": "网格容器中单项内容容器仅作为Grid子组件使用",
      "anchor": "griditem",
      "status": "found"
    },
    {
      "name": "Blank",
      "purpose": "空白填充组件自动填充容器主轴空余部分仅对Row/Column/Flex父组件生效",
      "anchor": "blank",
      "status": "found"
    },
    {
      "name": "Divider",
      "purpose": "分割线组件用于分割不同内容块或内容元素",
      "anchor": "divider",
      "status": "found"
    },
    {
      "name": "Badge",
      "purpose": "信息标记组件可附加在单个组件上用于信息提醒支持数字和字符串两种构造",
      "anchor": "badge",
      "status": "found"
    }
  ],
  "notableFindings": [
    "Flex组件存在二次布局开销对性能敏感场景建议用Column/Row替代",
    "Blank仅当父容器为Row/Column/Flex时生效不支持百分比设置",
    "Badge文档位于12_信息展示目录不在target_rel_dirs中需从信息展示目录引用",
    "Grid API 18+支持基于断点配置列数columnsTemplate支持auto-fill/auto-fit/auto-stretch自适应模式",
    "Column/Row未设置宽高时主轴自适应子组件大小Flex主轴默认撑满父容器",
    "Scroll从API 20+开始支持FREE自由滚动方向和缩放手势"
  ],
  "missingApis": []
}

{
  "module": "02-navigation.md",
  "group": "02 -- Navigation & Routing",
  "apiCount": 6,
  "apis": [
    {
      "name": "Tabs",
      "purpose": "通过页签进行内容视图切换的容器组件，每个页签对应一个内容视图",
      "anchor": "Tabs",
      "status": "found"
    },
    {
      "name": "TabContent",
      "purpose": "仅在 Tabs 中使用的页签内容视图组件",
      "anchor": "TabContent",
      "status": "found"
    },
    {
      "name": "NavRouter",
      "purpose": "导航组件（已停止维护，API 13 起废弃），推荐使用 NavPathStack + navDestination",
      "anchor": "NavRouter",
      "status": "found"
    },
    {
      "name": "NavDestination",
      "purpose": "Navigation 子页面的根容器，用于显示 Navigation 内容区",
      "anchor": "NavDestination",
      "status": "found"
    },
    {
      "name": "Navigation",
      "purpose": "路由导航的根视图容器，作为 Page 页面的根容器配合 NavPathStack 实现多级页面路由",
      "anchor": "Navigation",
      "status": "found"
    },
    {
      "name": "Router",
      "purpose": "基于 URL 的页面路由 API（不推荐，API 18 起废弃），推荐使用 Navigation 组件",
      "anchor": "Router",
      "status": "found"
    }
  ],
  "notableFindings": [
    "NavRouter 从 API 13 起停止维护，推荐使用 NavPathStack + navDestination 替代",
    "@ohos.router 从 API 18 起废弃 pushUrl/replaceUrl 等方法，推荐使用 Navigation 组件",
    "Navigation API 10+ 推荐使用 NavPathStack 配合 navDestination 进行页面路由，API 20+ 支持 HomePathInfo 指定导航主页",
    "NavPathStack API 12+ 可被继承，派生类可替代基类使用",
    "Tabs 仅支持 TabContent 作为子组件（及渲染控制类型），不支持自定义组件直接作为子组件"
  ],
  "missingApis": []
}

{
  "module": "03-state.md",
  "group": "03 — State Management",
  "apiCount": 10,
  "apis": [
    {
      "name": "@State",
      "purpose": "组件内部状态管理，状态变化自动触发UI刷新",
      "anchor": "state",
      "status": "found"
    },
    {
      "name": "@Prop",
      "purpose": "父组件到子组件的单向数据传递",
      "anchor": "prop",
      "status": "found"
    },
    {
      "name": "@Link",
      "purpose": "父组件与子组件之间的双向数据同步",
      "anchor": "link",
      "status": "found"
    },
    {
      "name": "@Provide",
      "purpose": "向子组件提供数据源，配合@Consume实现跨层级数据同步",
      "anchor": "provide",
      "status": "found"
    },
    {
      "name": "@Consume",
      "purpose": "接收祖先组件@Provide提供的数据，建立双向绑定",
      "anchor": "consume",
      "status": "found"
    },
    {
      "name": "@Observed",
      "purpose": "标记class为可观察对象，使属性变化可被状态管理V1追踪",
      "anchor": "observed",
      "status": "found"
    },
    {
      "name": "@ObjectLink",
      "purpose": "对@Observed装饰的class实例的属性进行双向数据同步",
      "anchor": "objectlink",
      "status": "found"
    },
    {
      "name": "@Watch",
      "purpose": "监听状态变量变化，变化时触发指定回调函数",
      "anchor": "watch",
      "status": "found"
    },
    {
      "name": "@StorageProp",
      "purpose": "与AppStorage建立单向绑定，组件读取但不写回修改",
      "anchor": "storageprop",
      "status": "found"
    },
    {
      "name": "@StorageLink",
      "purpose": "与AppStorage建立双向绑定，组件修改同步写回AppStorage",
      "anchor": "storagelink",
      "status": "found"
    }
  ],
  "notableFindings": [
    "@State/@Prop/@Link/@Provide/@Consume/@Observed/@ObjectLink V1装饰器在本地API参考中无独立签名文档，仅02_状态管理V1装饰器参数.md提供了ProvideOptions的allowOverride参数",
    "所有10个API均为内置装饰器，无需import导入",
    "V2状态管理API（AppStorageV2/PersistenceV2/UIUtils）位于@ohos.arkui.StateManagement模块，需 import { AppStorageV2, PersistenceV2, UIUtils } from '@kit.ArkUI'",
    "@StorageProp和@StorageLink依赖AppStorage运行时存在对应键值对，详见01_应用级变量的状态管理.md"
  ],
  "missingApis": []
}

{
  "module": "04-persistence.md",
  "group": "04 — Data Persistence",
  "apiCount": 4,
  "apis": [
    {
      "name": "relationalStore",
      "purpose": "创建或打开关系型数据库（RDB），提供本地 SQLite 数据的增删改查能力",
      "anchor": "relationalstore",
      "status": "found"
    },
    {
      "name": "preferences",
      "purpose": "提供 Key-Value 键值型轻量数据持久化，存储数字、字符串、布尔类型",
      "anchor": "preferences",
      "status": "found"
    },
    {
      "name": "PersistentStorage",
      "purpose": "将 AppStorage 中的属性持久化到文件，支持应用级 UI 状态持久化",
      "anchor": "persistentstorage",
      "status": "missing"
    },
    {
      "name": "Environment",
      "purpose": "将设备内置环境变量（如语言、颜色模式、字体缩放）存入 AppStorage",
      "anchor": "environment",
      "status": "missing"
    }
  ],
  "notableFindings": [
    "PersistentStorage 和 Environment 属于 ArkUI 状态管理（@kit.ArkUI），非 ArkData 模块。实际位于 02_应用框架/05_ArkUI（方舟UI框架）/02_ArkTS组件/28_状态管理与渲染控制/01_应用级变量的状态管理.md",
    "relationalStore 基于 SQLite，单条数据建议不超过 2MB，单次查询不超过 5000 条",
    "preferences 不支持进程并发安全，键最大 1024 字节，值最大 16MB"
  ],
  "missingApis": [
    "PersistentStorage",
    "Environment"
  ]
}

{
  "module": "06-dialogs.md",
  "group": "06 — Dialogs & Bottom Sheets",
  "apiCount": 6,
  "apis": [
    {
      "name": "CustomDialogController",
      "purpose": "通过 CustomDialogController 类控制自定义弹窗的创建、显示和关闭，配合 @CustomDialog 装饰器使用",
      "anchor": "customdialogcontroller",
      "status": "found"
    },
    {
      "name": "bindSheet",
      "purpose": "为组件绑定半模态页面（底部弹窗），支持自定义高度、多挡位切换和多种样式",
      "anchor": "bindsheet",
      "status": "found"
    },
    {
      "name": "AlertDialog",
      "purpose": "显示警告弹窗，可设置文本内容、按钮和响应回调",
      "anchor": "alertdialog",
      "status": "found"
    },
    {
      "name": "ActionSheet",
      "purpose": "显示列表选择弹窗，支持标题、消息和确认按钮",
      "anchor": "actionsheet",
      "status": "found"
    },
    {
      "name": "DatePickerDialog",
      "purpose": "根据指定日期范围创建日期滑动选择器并展示在弹窗上",
      "anchor": "datepickerdialog",
      "status": "found"
    },
    {
      "name": "TextPickerDialog",
      "purpose": "根据指定的选择范围创建文本选择器并展示在弹窗上",
      "anchor": "textpickerdialog",
      "status": "found"
    }
  ],
  "notableFindings": [
    "AlertDialog、ActionSheet、DatePickerDialog、TextPickerDialog 的 static show() 方法从 API version 18 开始废弃，需通过 UIContext 实例方法调用",
    "bindSheet 仅可在 Stage 模型下使用（从 API version 10 开始支持），不支持路由跳转",
    "CustomDialogController 推荐优先使用以获取弹窗样式与内容的最大灵活性",
    "所有弹窗方法都依赖 UI 执行上下文，推荐统一通过 getUIContext() 明确上下文后再调用"
  ],
  "missingApis": []
}

{
  "module": "07-calendar.md",
  "group": "07 — Date & Calendar Components",
  "apiCount": 3,
  "apis": [
    {
      "name": "DatePicker",
      "purpose": "滑动选择日期的组件，支持公历/农历切换、多档文本样式和多种日期显示模式",
      "anchor": "datepicker",
      "status": "found"
    },
    {
      "name": "CalendarPicker",
      "purpose": "下拉日历弹窗选择组件，支持日期选中、日期区间限制和禁用日期",
      "anchor": "calendarpicker",
      "status": "found"
    },
    {
      "name": "TimePicker",
      "purpose": "滑动选择时间的组件，支持12/24小时制切换、时分秒格式和循环滚动",
      "anchor": "timepicker",
      "status": "found"
    }
  ],
  "notableFindings": [
    "三个组件均位于09_按钮与选择目录，非target_rel_dirs指定的10_文本与输入",
    "CalendarPicker从API version 10开始支持，且Wearable设备不可用",
    "共享PickerTextStyle类型定义于ts-picker-common",
    "DatePicker相关弹窗为DatePickerDialog，TimePicker相关弹窗为TimePickerDialog，CalendarPicker相关弹窗为CalendarPickerDialog，均位于19_弹窗目录"
  ],
  "missingApis": []
}

{
  "module": "08-lifecycle.md",
  "group": "Lifecycle & Context",
  "apiCount": 6,
  "apis": [
    {
      "name": "UIAbility",
      "purpose": "带界面的应用组件，管理 UI 生命周期（Create/Foreground/Background/Destroy）和 WindowStage 生命周期",
      "anchor": "uiability",
      "status": "found"
    },
    {
      "name": "AbilityStage",
      "purpose": "Module 级别的组件管理器，用于资源预加载和 Module 状态维护",
      "anchor": "abilitystage",
      "status": "found"
    },
    {
      "name": "Want",
      "purpose": "对象间信息传递的载体，用于应用组件间传递启动参数和数据",
      "anchor": "want",
      "status": "found"
    },
    {
      "name": "Context",
      "purpose": "Stage 模型上下文基类，提供应用资源访问和应用级操作能力（import from common）",
      "anchor": "context",
      "status": "found"
    },
    {
      "name": "resourceManager",
      "purpose": "资源管理能力，获取字符串、颜色、图片等应用及系统资源",
      "anchor": "resourcemanager",
      "status": "found"
    },
    {
      "name": "window",
      "purpose": "窗口管理，提供窗口创建、销毁、属性设置及 WindowStage 页面加载能力",
      "anchor": "window",
      "status": "found"
    }
  ],
  "notableFindings": [
    "UIAbility、AbilityStage、Want、Context (Stage) 均仅限 Stage 模型下使用",
    "Stage 模型下通过 this.context.resourceManager 直接获取资源管理对象，无需额外导入 resourceManager 模块",
    "window 模块导入路径为 @kit.ArkUI（非 @kit.AbilityKit），与其他 Ability Kit API 分属不同 Kit",
    "Want 数据大小限制：API 23+ 为 200KB，API 22 及之前为 100KB，超大数据应使用 WriteRawDataBuffer 或 uri 传递",
    "UIAbilityContext 继承自 Context，UIAbility.context 属性类型即为 UIAbilityContext"
  ],
  "missingApis": []
}
